/// - S_t (Semantic)       :: MYELIN owns retrieval path state
/// - G_t^mem (Memory)     :: MYELIN owns the graph structure

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use chrono::{DateTime, Utc};

/// Φ_t: Phylactery — Append-only identity canon chain
///
/// Owned by AEON. Maintains the commit history and identity vector
/// across all sessions. This is the authoritative record of "who we are
/// and how we got here."
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Phylactery {
    /// Unique identity fingerprint (stable across sessions)
    pub identity_vector: String,

    /// Ordered list of canonical commits (who authorized what, when)
    pub commit_chain: Vec<IdentityCommit>,

    /// Current session anchor (links this session to the chain)
    pub current_anchor: Option<String>,

    /// Timestamp of last phylactery update
    pub last_updated: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct IdentityCommit {
    pub timestamp: DateTime<Utc>,
    pub authority: String,
    pub change: String,
    pub signature: Option<String>,
}

impl Default for Phylactery {
    fn default() -> Self {
        Self {
            identity_vector: String::new(),
            commit_chain: Vec::new(),
            current_anchor: None,
            last_updated: Utc::now(),
        }
    }
}

/// E_t: Economy — Neuro-credit state
///
/// Owned by ADCCL. Tracks computational budget, claim costs,
/// and spending patterns across reasoning layers.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EconomyState {
    /// Available credits for this reasoning session
    pub available_credits: f64,

    /// Credits spent so far
    pub spent_credits: f64,

    /// Per-layer spending breakdown
    pub layer_spending: HashMap<String, f64>,

    /// Cost multiplier for risky operations (>1.0 = penalized)
    pub risk_multiplier: f64,
}

impl Default for EconomyState {
    fn default() -> Self {
        Self {
            available_credits: 1000.0,
            spent_credits: 0.0,
            layer_spending: HashMap::new(),
            risk_multiplier: 1.0,
        }
    }
}

